+const char *VM_Version::VM_Features::print_numbers() const {
+  char *buf = NEW_RESOURCE_ARRAY(char, MAX_CPU_FEATURES);
+  stringStream ss(buf, MAX_CPU_FEATURES);
+  print_numbers(ss);
+  return buf;
