+bool VM_Crac::read_shm(int shmid) {
+  precond(shmid > 0);
+  CracSHM shm(shmid);
+  int shmfd = shm.open(O_RDONLY);
+  shm.unlink();
+  if (shmfd < 0) {
+    log_error(crac)("Cannot read restore parameters");
+    return false;
+  }
+  bool ret = _restore_parameters.read_from(shmfd);
+  close(shmfd);
+  return ret;
+}
