+bool VM_Crac::is_claimed_fd(int fd) {
+  typeArrayOop claimed_fds = typeArrayOop(JNIHandles::resolve_non_null(_fd_arr));
+  for (int j = 0; j < claimed_fds->length(); ++j) {
+    jint cfd = claimed_fds->int_at(j);
+    if (fd == cfd) {
+      return true;
+    }
+  }
+  return false;
+}
